import{_ as s,o as n,c as t,O as r}from"./chunks/framework.1e3ff9a3.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1775707265000}'),p={name:"guide/index.md"};function e(l,a,d,c,i,_){return n(),t("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Start Here</p><h1>开始使用</h1><div class="brand-hero__panel"><span class="brand-pill">Guide First</span><strong>第一次来最容易浪费时间的，不是功能不够，而是不知道该从哪条路开始。</strong><p>所以这里先把入口、角色和阅读顺序分清楚。</p></div><p class="brand-lead"> 这组页面不是再讲一遍产品概念，而是帮第一次接触 SmartFlow 的人快速判断： <strong>我该先体验、先看文档、先接 CLI，还是直接走交付沟通。</strong></p><div class="brand-chip-list"><span class="brand-chip">先体验</span><span class="brand-chip">再登录</span><span class="brand-chip">CLI 接入</span><span class="brand-chip">交付沟通</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./getting-started.html">看快速开始</a><a class="cta-button" href="./faq.html">看常见问题</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>SMARTFLOW // START HERE</span><span>GUIDE 01</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">path_a</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">experience</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">login</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">product docs</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">path_b</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">local scripts</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">cli</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">manifest</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">run</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">path_c</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">customer delivery</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">tenant</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">hot update</span></span></div><div class="matrix-panel__callout">START WITH THE RIGHT PATH, NOT WITH RANDOM MENU EXPLORATION</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">entry</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">public</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">docs</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">ready</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">route</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">guided</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Path A</p><h2>先体验一遍执行链路</h2><p>如果你还在判断这套平台到底是不是你需要的东西，建议先走公开体验路径，再决定是否继续注册、登录或预约演示。</p></article><article class="brand-card"><p class="brand-kicker">Path B</p><h2>你已经有本地脚本</h2><p>如果你手上已经有本地脚本目录，重点就不是继续看营销介绍，而是直接看 <code>smartflow-cli</code> 当前已经能打通到哪一步。</p></article><article class="brand-card"><p class="brand-kicker">Path C</p><h2>你要正式交付客户</h2><p>如果你是带着客户项目、团队协作或交付需求来的，重点应该放在客户流程、部署方式和交付边界，而不是免费入口细节。</p></article></section><section class="brand-card"><p class="brand-kicker">Public Entry</p><h2>当前公开可走的正式入口</h2><table><thead><tr><th>入口类型</th><th>当前怎么理解</th><th>适合谁</th><th>下一步看哪里</th></tr></thead><tbody><tr><td>公开体验链路</td><td>当前正式公开口径里已经包含 <code>/experience</code>、<code>/login</code>、<code>/register</code></td><td>第一次接触平台的人</td><td><a href="./getting-started.html">快速开始</a></td></tr><tr><td>产品文档</td><td>解释平台是什么、怎么交付、怎么部署、怎么演进</td><td>产品、售前、技术负责人</td><td><a href="../product/index.html">产品概览</a></td></tr><tr><td>CLI 文档</td><td>说明本地登录、脚本注册、执行和 Agent 骨架的当前边界</td><td>开发者、本地接入场景</td><td><a href="../product/cli.html">CLI 指引</a></td></tr><tr><td>客户交付文档</td><td>说明客户怎么使用、平台怎么交付、脚本怎么热更新</td><td>交付负责人、项目负责人</td><td><a href="../product/customer-flow.html">客户流程 / 交付</a></td></tr><tr><td>联系入口</td><td>用于试用、演示预约、交付沟通和合作咨询</td><td>需要继续推进的人</td><td><a href="../contact.html#lead-form">联系我</a></td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Role Based</p><h2>不同角色，建议从哪里开始</h2><div class="brand-grid brand-grid--four"><article class="brand-card brand-card--nested"><h3>个人开发者</h3><p>先看快速开始，再看 CLI 指引，最后再判断是否需要更深的团队或企业路径。</p></article><article class="brand-card brand-card--nested"><h3>小团队负责人</h3><p>先看产品概览和客户流程 / 交付，再决定是否需要演示或交付沟通。</p></article><article class="brand-card brand-card--nested"><h3>售前 / 方案人员</h3><p>先看对外资料，再回到产品概览、部署方式和客户流程，保证口径一致。</p></article><article class="brand-card brand-card--nested"><h3>企业客户</h3><p>先看客户流程 / 交付和部署方式，再确认租户隔离、热更新和后续合作边界。</p></article></div></section><section class="brand-card"><p class="brand-kicker">Reading Order</p><h2>建议阅读顺序</h2><div class="brand-link-grid"><a class="brand-link-card" href="./getting-started.html"><span>Step 01</span><strong>快速开始</strong><p>先确认现在公开的正式入口、体验路径和当前已成立的能力边界。</p></a><a class="brand-link-card" href="../product/index.html"><span>Step 02</span><strong>产品概览</strong><p>再理解平台到底是什么，不是什么，以及现在最准确的公开定义。</p></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Step 03</span><strong>客户流程 / 交付</strong><p>如果你关心客户怎么用、平台怎么交付、脚本怎么热更新，直接看这页。</p></a><a class="brand-link-card" href="../product/cli.html"><span>Step 04</span><strong>CLI 指引</strong><p>如果你已经有本地脚本目录，这页比泛泛介绍更有价值。</p></a><a class="brand-link-card" href="./faq.html"><span>Step 05</span><strong>常见问题</strong><p>把“是不是聊天系统、会不会串租户、能不能直接上线”这类问题一次看清。</p></a><a class="brand-link-card" href="../materials/index.html"><span>Step 06</span><strong>对外资料</strong><p>如果你要做介绍、讲解、演示或对外表达，可以继续看这里。</p></a></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>想继续推进，就按你的目标选下一页</h2><p class="brand-lead">先体验、先接 CLI、先做客户交付，三条路都成立，但不该混着看。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./getting-started.html"><span>Guide</span><strong>快速开始</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="../product/cli.html"><span>CLI</span><strong>CLI 指引</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>联系我</strong></a></div></div></section></div>',1)]))}const h=s(p,[["render",e]]);export{m as __pageData,h as default};
